// validate.ts
import { User, Order, Product } from './types';

function isValidId(id: string): boolean {
  const entityType = id.slice(0, 5);
  return id.startsWith(entityType) && !id.includes(' ');
}

function isValidTimestamp(timestamp: number): boolean {
  return typeof timestamp === 'number' && !isNaN(timestamp);
}

function isValidCents(value: number): boolean {
  return typeof value === 'number' && !isNaN(value) && value % 1 === 0;
}

function validateUser(user: User): boolean {
  return (
    isValidId(user.id) &&
    typeof user.name === 'string' &&
    isValidTimestamp(user.timestamp) &&
    isValidCents(user.balance)
  );
}

function validateOrder(order: Order): boolean {
  return (
    isValidId(order.id) &&
    isValidId(order.user_id) &&
    isValidId(order.product_id) &&
    isValidTimestamp(order.timestamp) &&
    isValidCents(order.amount)
  );
}

function validateProduct(product: Product): boolean {
  return (
    isValidId(product.id) &&
    typeof product.name === 'string' &&
    isValidTimestamp(product.timestamp) &&
    isValidCents(product.price)
  );
}

export function validateAllData(data: { users?: User[]; orders?: Order[]; products?: Product[] }): boolean {
  if (data.users) {
    for (const user of data.users) {
      if (!validateUser(user)) {
        console.error(`Invalid User: ${JSON.stringify(user)}`);
        return false;
      }
    }
  }

  if (data.orders) {
    for (const order of data.orders) {
      if (!validateOrder(order)) {
        console.error(`Invalid Order: ${JSON.stringify(order)}`);
        return false;
      }
    }
  }

  if (data.products) {
    for (const product of data.products) {
      if (!validateProduct(product)) {
        console.error(`Invalid Product: ${JSON.stringify(product)}`);
        return false;
      }
    }
  }

  return true;
}
