  if (isNaN(user.balance) || !Number.isInteger(user.balance)) {
    errors.push(`User balance must be integer cents: ${user.balance}`);
  }

  // Check timestamp is Unix epoch milliseconds
  if (isNaN(user.timestamp) || !Number.isInteger(user.timestamp)) {
    errors.push(`User timestamp must be integer milliseconds: ${user.timestamp}`);
  }

  return errors;
}

function validateOrder(order: Order): string[] {
  const errors: string[] = [];

  // Check ID format
  if (!order.id.startsWith("order_")) {
    errors.push(`Order ID must start with "order_": ${order.id}`);
  }

  // Check user_id format
  if (!order.user_id.startsWith("user_")) {
    errors.push(`Order user_id must start with "user_": ${order.user_id}`);
  }

  // Check product_id format
  if (!order.product_id.startsWith("product_")) {
    errors.push(`Order product_id must start with "product_": ${order.product_id}`);
  }

  // Check price is integer cents
  if (isNaN(order.price) || !Number.isInteger(order.price)) {
    errors.push(`Order price must be integer cents: ${order.price}`);
  }

  // Check timestamp is Unix epoch milliseconds
  if (isNaN(order.timestamp) || !Number.isInteger(order.timestamp)) {
    errors.push(`Order timestamp must be integer milliseconds: ${order.timestamp}`);
  }

  return errors;
}

function validateProduct(product: Product): string[] {
  const errors: string[] = [];

  // Check ID format
  if (!product.id.startsWith("product_")) {
    errors.push(`Product ID must start with "product_": ${product.id}`);
  }

  // Check price is integer cents
  if (isNaN(product.price) || !Number.isInteger(product.price)) {
    errors.push(`Product price must be integer cents: ${product.price}`);
  }

  return errors;
}

export function validateAll(data: { users: User[], orders: Order[], products: Product[] }): string[] {
  const errors: string[] = [];

  // Validate users
  data.users.forEach(user => {
    errors.push(...validateUser(user));
  });

  // Validate orders
  data.orders.forEach(order => {
    errors.push(...validateOrder(order));
  });

  // Validate products
  data.products.forEach(product => {
    errors.push(...validateProduct(product));
  });

  return errors;
}
