// Phase 4: validate.ts
import { User, Order, Product } from './types';

function isValidId(id: string): boolean {
  return id.startsWith('user_') || id.startsWith('order_') || id.startsWith('product_');
}

function isValidTimestamp(timestamp: number): boolean {
  return typeof timestamp === 'number' && !isNaN(timestamp);
}

function isValidCents(value: number): boolean {
  return typeof value === 'number' && !isNaN(value) && Number.isInteger(value);
}

function validateUser(user: User): boolean {
  return (
    isValidId(user.id) &&
    isValidCents(user.balance) &&
    isValidTimestamp(user.lastActiveTimestamp)
  );
}

function validateOrder(order: Order): boolean {
  return (
    isValidId(order.id) &&
    isValidCents(order.totalAmountCents) &&
    isValidCents(order.paymentMethodCents) &&
    isValidTimestamp(order.createdAt) &&
    isValidTimestamp(order.updatedAt)
  );
}

function validateProduct(product: Product): boolean {
  return (
    isValidId(product.id) &&
    isValidCents(product.priceCents) &&
    isValidTimestamp(product.createdAt)
  );
}

export function validateData(data: { users: User[], orders: Order[], products: Product[] }): { valid: boolean, errors: string[] } {
  const errors: string[] = [];

  data.users.forEach((user, index) => {
    if (!validateUser(user)) {
      errors.push(`User ${index + 1}: ${validateUser(user) ? 'Valid' : 'Invalid'}`);
    }
  });

  data.orders.forEach((order, index) => {
    if (!validateOrder(order)) {
      errors.push(`Order ${index + 1}: ${validateOrder(order) ? 'Valid' : 'Invalid'}`);
    }
  });

  data.products.forEach((product, index) => {
    if (!validateProduct(product)) {
      errors.push(`Product ${index + 1}: ${validateProduct(product) ? 'Valid' : 'Invalid'}`);
    }
  });

  return { valid: errors.length === 0, errors };
}
