// validate.ts
import { User, Order, Product } from './types';

export function validateData(data: any): {
    errors: string[];
} {
    const errors: string[] = [];

    // Validate Users
    if (!Array.isArray(data.users)) {
        errors.push('Users must be an array');
    }
    data.users.forEach((user, index) => {
        if (typeof user.id !== 'string' || !user.id.startsWith('user_')) {
            errors.push(`User ${index + 1} ID is invalid`);
        }
        if (typeof user.balanceCents !== 'number') {
            errors.push(`User ${index + 1} balance must be a number of cents`);
        }
    });

    // Validate Orders
    if (!Array.isArray(data.orders)) {
        errors.push('Orders must be an array');
    }
    data.orders.forEach((order, index) => {
        if (typeof order.id !== 'string' || !order.id.startsWith('order_')) {
            errors.push(`Order ${index + 1} ID is invalid`);
        }
        if (typeof order.totalCents !== 'number') {
            errors.push(`Order ${index + 1} total must be a number of cents`);
        }
    });

    // Validate Products
    if (!Array.isArray(data.products)) {
        errors.push('Products must be an array');
    }
    data.products.forEach((product, index) => {
        if (typeof product.id !== 'string' || !product.id.startsWith('product_')) {
            errors.push(`Product ${index + 1} ID is invalid`);
        }
        if (typeof product.priceCents !== 'number') {
            errors.push(`Product ${index + 1} price must be a number of cents`);
        }
    });

    // Validate Timestamps
    data.users.forEach(user => {
        if (!Number.isInteger(user.timestampMs)) {
            errors.push('User timestamp must be an integer Unix epoch milliseconds');
        }
    });
    data.orders.forEach(order => {
        if (!Number.isInteger(order.timestampMs)) {
            errors.push('Order timestamp must be an integer Unix epoch milliseconds');
        }
    });
    data.products.forEach(product => {
        if (!Number.isInteger(product.timestampMs)) {
            errors.push('Product timestamp must be an integer Unix epoch milliseconds');
        }
    });

    return { errors };
}
