// validate.ts
import { User, Order, Product } from './types';

export function validateData(data: any): boolean {
    const results = {
        users: [],
        products: [],
        orders: []
    };

    // Validate Users
    if (Array.isArray(data.users)) {
        data.users.forEach(user => {
            results.users.push(validateUser(user));
        });
    }

    // Validate Products
    if (Array.isArray(data.products)) {
        data.products.forEach(product => {
            results.products.push(validateProduct(product));
        });
    }

    // Validate Orders
    if (Array.isArray(data.orders)) {
        data.orders.forEach(order => {
            results.orders.push(validateOrder(order, data.users, data.products));
        });
    }

    return Object.values(results).every(validated => validated.every(result => result));
}

export function validateUser(user: any): boolean {
    const errors = [];

    if (!user.id || !user.id.startsWith('user_')) {
        errors.push("Invalid user ID");
    }

    if (typeof user.created_at !== 'number') {
        errors.push("Invalid Unix epoch timestamp for user creation date");
    }

    return errors.length === 0;
}

export function validateProduct(product: any): boolean {
    const errors = [];

    if (!product.id || !product.id.startsWith('product_')) {
        errors.push("Invalid product ID");
    }

    if (typeof product.price_cents !== 'number') {
        errors.push("Price must be integer cents, not dollars");
    }

    return errors.length === 0;
}

export function validateOrder(order: any, users: User[], products: Product[]): boolean {
    const errors = [];

    if (!order.id || !order.id.startsWith('order_')) {
        errors.push("Invalid order ID");
    }

    if (typeof order.created_at !== 'number') {
        errors.push("Invalid Unix epoch timestamp for order creation date");
    }

    // Additional order-specific validation
    const user = users.find(u => u.id === order.user_id);
    const product = products.find(p => p.id === order.product_id);

    if (!user || !product) {
        errors.push("Order references non-existent user or product");
    }

    return errors.length === 0;
}
