// validate.ts
import { MonetaryValue, Timestamp } from './types';
import { generateSampleData } from './generate';

export function validateData(data: {
    users: User[];
    orders: Order[];
    products: Product[];
}): string[] {
    const errors: string[] = [];

    // Validate IDs
    for (const user of data.users) {
        if (!user.id.startsWith('user_')) {
            errors.push(`Invalid user ID format: ${user.id}`);
        }
    }

    for (const order of data.orders) {
        if (!order.id.startsWith('order_') || !order.userId.startsWith('user_')) {
            errors.push(`Invalid order or user ID format`);
        }
    }

    for (const product of data.products) {
        if (!product.id.startsWith('product_')) {
            errors.push(`Invalid product ID format: ${product.id}`);
        }
    }

    // Validate Monetary Values
    for (const order of data.orders) {
        if (!Number.isInteger(order.totalCents / 100)) {
            errors.push(`Order total cents must be integer: ${order.totalCents}`);
        }
    }

    for (const product of data.products) {
        if (!Number.isInteger(product.priceCents.cents / 100)) {
            errors.push(`Product price cents must be integer: ${product.priceCents.cents}`);
        }
    }

    // Validate Timestamps
    for (const order of data.orders) {
        const timestamp = order.timestamp;
        if (isNaN(timestamp.millisecondsSinceEpoch) || 
            !Number.isInteger(timestamp.millisecondsSinceEpoch)) {
            errors.push(`Invalid timestamp format: ${timestamp.millisecondsSinceEpoch}`);
        }
    }

    return errors;
}
